#include <bits/stdc++.h>using namespace std;typedef long long ll;const int MOD =1e9+7;int main(){    int t;    cin>>t;    while(t--){        int n;        cin>>n;        vector<int>a(n);        for(int i=0;i<n;i++){            cin>>a[i];        }        sort(a.begin(),a.end());         vector<int>b(n);        for(int i=0;i<n;i++){            cin>>b[i];        }        sort(b.begin(),b.end(),greater<>());        ll result =1;        for(int i=0;i<n;i++){            int g_c = a.size() - (upper_bound(a.begin(),a.end(),b[i])-a.begin());            result = result * max(g_c - i,0)%MOD;         }        cout<<result<<endl;    }}